/// Evaluate prmx crossbar routing using probed tables.
pub fn eval_prmx(a: &[u8; 128], m: &[u64; 13]) -> [u8; 512] {
    let mut r = [0u8; 512];
    for mbit in 0..789usize {
        if (m[mbit / 64] >> (mbit % 64)) & 1 == 0 { continue; }
        let idx = PRMX_MBIT_IDX[mbit];
        if idx < 0 { continue; }
        let idx = idx as usize;
        let start = PRMX_OVR_START[idx] as usize;
        let end = PRMX_OVR_START[idx + 1] as usize;
        for j in start..end {
            let out = PRMX_OVR_OUT[j] as usize;
            r[out] |= a[PRMX_OVR_IN[j] as usize];
        }
    }
    r
}

