/// Evaluate prmy Y-perm routing using probed lookup tables.
pub fn eval_prmy(a_nibbles: &[u8; 128], pmode: u32) -> [u8; 512] {
    let mut r = [0u8; 512];
    let pbit = pmode.trailing_zeros();
    if pbit >= 26 { return r; }
    let table: &[i16; 512] = match pbit {
        0 => &PRMY_ROUTE_0,
        1 => &PRMY_ROUTE_1,
        2 => &PRMY_ROUTE_2,
        3 => &PRMY_ROUTE_3,
        4 => &PRMY_ROUTE_4,
        5 => &PRMY_ROUTE_5,
        6 => &PRMY_ROUTE_6,
        7 => &PRMY_ROUTE_7,
        8 => &PRMY_ROUTE_8,
        9 => &PRMY_ROUTE_9,
        10 => &PRMY_ROUTE_10,
        11 => &PRMY_ROUTE_11,
        12 => &PRMY_ROUTE_12,
        13 => &PRMY_ROUTE_13,
        14 => &PRMY_ROUTE_14,
        15 => &PRMY_ROUTE_15,
        16 => &PRMY_ROUTE_16,
        17 => &PRMY_ROUTE_17,
        18 => &PRMY_ROUTE_18,
        19 => &PRMY_ROUTE_19,
        20 => &PRMY_ROUTE_20,
        21 => &PRMY_ROUTE_21,
        22 => &PRMY_ROUTE_22,
        23 => &PRMY_ROUTE_23,
        24 => &PRMY_ROUTE_24,
        25 => &PRMY_ROUTE_25,
        _ => return r,
    };
    for i in 0..512 {
        let src = table[i];
        if src >= 0 {
            r[i] = a_nibbles[src as usize];
        }
    }
    r
}
